1	//! First-run wizard panels.
2	//!
3	//! show_wizard() is the entry point. It dispatches to the correct step panel
4	//! based on first_incomplete_step(), re-probes after each action, and signals
5	//! completion when is_setup_complete() is true.
6	//!
7	//! All panels are feature-gated to `gui` — only compiled when eframe is present.
8	
9	/// Re-export all wizard types and the `show_wizard` entry point when the `gui` feature is enabled.
10	#[cfg(feature = "gui")]
11	pub use inner::*;
12	
13	#[cfg(feature = "gui")]
14	mod inner {
15	    use std::io::Read;
16	    use std::path::PathBuf;
17	    use std::sync::{Arc, Mutex};
18	
19	    use eframe::egui;
20	    use evdev::{Device, EventSummary};
21	    use tracing::{error, info};
22	
23	    use crate::ui::first_run::{FirstRunState, SetupStep};
24	    use crate::ui::probe;
25	
26	    const MODEL_URL: &str =
27	        "https://huggingface.co/ggerganov/whisper.cpp/resolve/main/ggml-tiny.en.bin";
28	
29	    // ── Download state ───────────────────────────────────────────────────────
30	
31	    /// Progress state of the background model download.
32	    #[derive(Debug, Clone, PartialEq)]
33	    pub enum DownloadStatus {
34	        /// No download in progress.
35	        Idle,
36	        /// Download underway; `total` is `None` when the server omits Content-Length.
37	        Downloading { received: u64, total: Option<u64> },
38	        /// Download finished and the file has been moved into place.
39	        Done,
40	        /// Download failed; the inner string is a human-readable error message.
41	        Failed(String),
42	    }
43	
44	    /// Shared state for the model download background thread.
45	    pub struct ModelDownloadState {
46	        /// Current download progress, shared with the download thread via `Arc<Mutex<_>>`.
47	        pub status: Arc<Mutex<DownloadStatus>>,
48	        /// Join handle for the download thread; `None` when no download is running.
49	        pub handle: Option<std::thread::JoinHandle<()>>,
50	    }
51	
52	    impl ModelDownloadState {
53	        /// Construct initial state with `Idle` status and no thread handle.
54	        pub fn new() -> Self {
55	            Self {
56	                status: Arc::new(Mutex::new(DownloadStatus::Idle)),
57	                handle: None,
58	            }
59	        }
60	
61	        /// Return a clone of the current download status without blocking on failure.
62	        pub fn current(&self) -> DownloadStatus {
63	            self.status.lock().map(|g| g.clone()).unwrap_or(DownloadStatus::Idle)
64	        }
65	
66	        /// True while the download thread is actively transferring bytes.
67	        pub fn is_running(&self) -> bool {
68	            matches!(self.current(), DownloadStatus::Downloading { .. })
69	        }
70	    }
71	
72	    impl Default for ModelDownloadState {
73	        fn default() -> Self {
74	            Self::new()
75	        }
76	    }
77	
78	    // ── Uinput setup state ───────────────────────────────────────────────────
79	
80	    /// Lifecycle state of a single privileged uinput setup action (modprobe or usermod).
81	    #[derive(Debug, Clone, PartialEq)]
82	    pub enum SetupActionStatus {
83	        /// Action has not been initiated yet.
84	        Idle,
85	        /// pkexec subprocess is running; poll the thread handle to detect completion.
86	        Running,
87	        /// Action completed successfully.
88	        Done,
89	        /// Action failed; the inner string is a human-readable error message.
90	        Failed(String),
91	    }
92	
93	    /// Per-action status for the two privileged uinput setup steps.
94	    pub struct UinputSetupState {
95	        /// Status of the `modprobe uinput` step.
96	        pub modprobe: SetupActionStatus,
97	        /// Status of the `usermod -aG input` step.
98	        pub usermod: SetupActionStatus,
99	        /// Join handle for the modprobe pkexec thread; `None` when not running.
100	        pub modprobe_handle: Option<std::thread::JoinHandle<Result<(), String>>>,
101	        /// Join handle for the usermod pkexec thread; `None` when not running.
102	        pub usermod_handle: Option<std::thread::JoinHandle<Result<(), String>>>,
103	    }
104	
105	    impl UinputSetupState {
106	        /// Construct with all actions in `Idle` state and no thread handles.
107	        pub fn new() -> Self {
108	            Self {
109	                modprobe: SetupActionStatus::Idle,
110	                usermod: SetupActionStatus::Idle,
111	                modprobe_handle: None,
112	                usermod_handle: None,
113	            }
114	        }
115	    }
116	
117	    impl Default for UinputSetupState {
118	        fn default() -> Self {
119	            Self::new()
120	        }
121	    }
