123	    // ── PTT capture state ────────────────────────────────────────────────────
124	
125	    /// Shared state for the PTT key capture background thread.
126	    pub struct PttCaptureState {
127	        /// True while the capture thread is waiting for a keypress.
128	        pub listening: bool,
129	        /// Receives the evdev key name from the capture thread when a key is pressed.
130	        pub captured_key: Arc<Mutex<Option<String>>>,
131	        /// Join handle for the capture thread; `None` when not running.
132	        pub handle: Option<std::thread::JoinHandle<()>>,
133	        /// Last capture error message, shown in the wizard UI.
134	        pub error: Option<String>,
135	    }
136	
137	    impl PttCaptureState {
138	        /// Construct with `listening = false` and no captured key or thread.
139	        pub fn new() -> Self {
140	            Self {
141	                listening: false,
142	                captured_key: Arc::new(Mutex::new(None)),
143	                handle: None,
144	                error: None,
145	            }
146	        }
147	
148	        /// True when the thread has finished and deposited a key name.
149	        pub fn has_result(&self) -> bool {
150	            self.captured_key.lock().map(|g| g.is_some()).unwrap_or(false)
151	        }
152	
153	        /// Take the captured key name, leaving None in its place.
154	        pub fn take_result(&self) -> Option<String> {
155	            self.captured_key.lock().ok()?.take()
156	        }
157	    }
158	
159	    impl Default for PttCaptureState {
160	        fn default() -> Self {
161	            Self::new()
162	        }
163	    }
