264	    // ── Step: CreateConfig ───────────────────────────────────────────────────
265	
266	    fn show_create_config(
267	        ui: &mut egui::Ui,
268	        state: &mut FirstRunState,
269	        config_example_contents: &str,
270	        hd2_profile_contents: &str,
271	    ) {
272	        let target = crate::ui::probe::config_path_for_display();
273	        ui.heading("Step 1 of 4: Create config file");
274	        ui.add_space(8.0);
275	        ui.label(format!("Target: {target}"));
276	        ui.add_space(12.0);
277	
278	        if ui.button("Copy example config").clicked() {
279	            let target_path = PathBuf::from(&target);
280	            let parent = target_path.parent().unwrap_or(&target_path);
281	            match std::fs::create_dir_all(parent)
282	                .and_then(|_| std::fs::write(&target_path, config_example_contents))
283	            {
284	                Ok(()) => {
285	                    info!(path = %target, "Config file created");
286	                    install_default_profile(hd2_profile_contents);
287	                    *state = probe::run();
288	                }
289	                Err(e) => {
290	                    error!(reason = %e, "Failed to write config file");
291	                    ui.colored_label(egui::Color32::RED, format!("Error: {e}"));
292	                }
293	            }
294	        }
295	
296	        ui.add_space(8.0);
297	        ui.label("After copying, edit the file to set your audio device and PTT key.");
298	    }
