300	    /// Write the bundled hd2 profile to the XDG profiles directory if not already present.
301	    fn install_default_profile(hd2_profile_contents: &str) {
302	        let profiles_dir = xdg::BaseDirectories::with_prefix("vibe-attack")
303	            .get_config_home()
304	            .map(|p| p.join("profiles"));
305	
306	        let Some(dir) = profiles_dir else {
307	            error!("Could not resolve XDG config path for profiles");
308	            return;
309	        };
310	
311	        let dest = dir.join("hd2.yaml");
312	        if dest.exists() {
313	            info!(path = %dest.display(), "hd2 profile already present — skipping");
314	            return;
315	        }
316	
317	        if let Err(e) = std::fs::create_dir_all(&dir) {
318	            error!(reason = %e, "Failed to create profiles directory");
319	            return;
320	        }
321	
322	        match std::fs::write(&dest, hd2_profile_contents) {
323	            Ok(()) => info!(path = %dest.display(), "Default hd2 profile installed"),
324	            Err(e) => error!(reason = %e, path = %dest.display(), "Failed to write hd2 profile"),
325	        }
326	    }
