328	    // ── Step: InstallModel ───────────────────────────────────────────────────
329	
330	    fn show_install_model(
331	        ui: &mut egui::Ui,
332	        state: &mut FirstRunState,
333	        dl: &mut ModelDownloadState,
334	    ) {
335	        let model_path = crate::ui::probe::model_path_for_display();
336	
337	        ui.heading("Step 2 of 4: Install whisper model");
338	        ui.add_space(8.0);
339	        ui.label(format!("Target: {model_path}"));
340	        ui.add_space(12.0);
341	
342	        match dl.current() {
343	            DownloadStatus::Idle => {
344	                ui.label("~75 MB download from HuggingFace.");
345	                ui.add_space(8.0);
346	                if ui.button("Download model").clicked() {
347	                    let status = Arc::clone(&dl.status);
348	                    let dest = model_path.clone();
349	                    let handle = std::thread::spawn(move || {
350	                        download_model(status, &dest);
351	                    });
352	                    dl.handle = Some(handle);
353	                    // Immediately set to downloading so next frame shows progress
354	                    if let Ok(mut g) = dl.status.lock() {
355	                        *g = DownloadStatus::Downloading { received: 0, total: None };
356	                    }
357	                }
358	            }
359	            DownloadStatus::Downloading { received, total } => {
360	                ui.spinner();
361	                match total {
362	                    Some(total) if total > 0 => {
363	                        let frac = received as f32 / total as f32;
364	                        ui.add(
365	                            egui::ProgressBar::new(frac)
366	                                .desired_width(300.0)
367	                                .text(format!(
368	                                    "{:.1} / {:.1} MB",
369	                                    received as f64 / 1_048_576.0,
370	                                    total as f64 / 1_048_576.0
371	                                )),
372	                        );
373	                    }
374	                    _ => {
375	                        ui.label(format!(
376	                            "Downloading… {:.1} MB received",
377	                            received as f64 / 1_048_576.0
378	                        ));
379	                    }
380	                }
381	                // Fast repaint while downloading
382	                ui.ctx().request_repaint_after(std::time::Duration::from_millis(250));
383	            }
384	            DownloadStatus::Done => {
385	                ui.colored_label(egui::Color32::GREEN, "Download complete.");
386	                ui.add_space(4.0);
387	                if ui.button("Re-check").clicked() {
388	                    *state = probe::run();
389	                }
390	            }
391	            DownloadStatus::Failed(msg) => {
392	                ui.colored_label(egui::Color32::RED, format!("Download failed: {msg}"));
393	                ui.add_space(8.0);
394	                if ui.button("Retry").clicked() {
395	                    if let Ok(mut g) = dl.status.lock() {
396	                        *g = DownloadStatus::Idle;
397	                    }
398	                }
399	            }
400	        }
401	    }
