494	    // ── Step: SetupUinput ────────────────────────────────────────────────────
495	
496	    fn show_setup_uinput(
497	        ui: &mut egui::Ui,
498	        state: &mut FirstRunState,
499	        uinput: &mut UinputSetupState,
500	    ) {
501	        // Request repaint while an action is running.
502	        if matches!(uinput.modprobe, SetupActionStatus::Running)
503	            || matches!(uinput.usermod, SetupActionStatus::Running)
504	        {
505	            ui.ctx().request_repaint_after(std::time::Duration::from_millis(200));
506	        }
507	
508	        ui.heading("Step 3 of 4: Set up uinput access");
509	        ui.add_space(8.0);
510	        ui.label("Vibe Attack needs /dev/uinput to inject key events into your game.");
511	        ui.add_space(12.0);
512	
513	        // --- Action 1: load module ---
514	        ui.label("1. Load the uinput kernel module:");
515	        ui.add_space(4.0);
516	        ui.horizontal(|ui| {
517	            let button_text = match &uinput.modprobe {
518	                SetupActionStatus::Idle => "Load module",
519	                SetupActionStatus::Running => "Loading…",
520	                SetupActionStatus::Done => "✓ Loaded",
521	                SetupActionStatus::Failed(_) => "Retry",
522	            };
523	            let enabled = !matches!(uinput.modprobe, SetupActionStatus::Running);
524	            if ui.add_enabled(enabled, egui::Button::new(button_text)).clicked() {
525	                uinput.modprobe = SetupActionStatus::Running;
526	                let handle = std::thread::spawn(|| run_pkexec(&["modprobe", "uinput"]));
527	                uinput.modprobe_handle = Some(handle);
528	            }
529	            if let SetupActionStatus::Failed(ref msg) = uinput.modprobe {
530	                ui.colored_label(egui::Color32::RED, msg.as_str());
531	            }
532	        });
533	        ui.add_space(4.0);
534	        ui.label("Optional — persist across reboots:");
535	        copy_command_row(
536	            ui,
537	            "echo \"uinput\" | sudo tee /etc/modules-load.d/uinput.conf",
538	        );
539	        ui.add_space(12.0);
540	
541	        // --- Action 2: add to input group ---
542	        ui.label("2. Add yourself to the input group:");
543	        ui.add_space(4.0);
544	        ui.horizontal(|ui| {
545	            let button_text = match &uinput.usermod {
546	                SetupActionStatus::Idle => "Add to input group",
547	                SetupActionStatus::Running => "Running…",
548	                SetupActionStatus::Done => "✓ Added",
549	                SetupActionStatus::Failed(_) => "Retry",
550	            };
551	            let enabled = !matches!(uinput.usermod, SetupActionStatus::Running);
552	            if ui.add_enabled(enabled, egui::Button::new(button_text)).clicked() {
553	                let username = std::env::var("USER").unwrap_or_default();
554	                uinput.usermod = SetupActionStatus::Running;
555	                let handle = std::thread::spawn(move || {
556	                    run_pkexec(&["usermod", "-aG", "input", &username])
557	                });
558	                uinput.usermod_handle = Some(handle);
559	            }
560	            if let SetupActionStatus::Failed(ref msg) = uinput.usermod {
561	                ui.colored_label(egui::Color32::RED, msg.as_str());
562	            }
563	        });
564	        ui.add_space(8.0);
565	
566	        ui.label("3. Apply the group change without logging out (run in your terminal):");
567	        copy_command_row(ui, "newgrp input");
568	        ui.add_space(8.0);
569	
570	        ui.colored_label(
571	            egui::Color32::YELLOW,
572	            "Note (systemd v258+ / CachyOS 2025+): use the 'input' group, not 'uinput'.",
573	        );
574	
575	        ui.add_space(12.0);
576	        if ui.button("Re-check").clicked() {
577	            *state = probe::run();
578	        }
579	    }
