581	    /// Run a command via pkexec (polkit) and return Ok(()) on exit 0, Err(msg) otherwise.
582	    fn run_pkexec(args: &[&str]) -> Result<(), String> {
583	        let mut cmd_args = vec!["pkexec"];
584	        cmd_args.extend_from_slice(args);
585	
586	        let status = std::process::Command::new(cmd_args[0])
587	            .args(&cmd_args[1..])
588	            .status()
589	            .map_err(|e| format!("failed to run pkexec: {e}"))?;
590	
591	        if status.success() {
592	            Ok(())
593	        } else {
594	            Err(format!(
595	                "command exited with code {}",
596	                status.code().unwrap_or(-1)
597	            ))
598	        }
599	    }
600	
601	    /// Render a dark code block with a "Copy" button on the right.
602	    fn copy_command_row(ui: &mut egui::Ui, cmd: &str) {
603	        ui.horizontal(|ui| {
604	            egui::Frame::NONE
605	                .fill(egui::Color32::from_gray(30))
606	                .inner_margin(egui::Margin::same(6))
607	                .show(ui, |ui| {
608	                    ui.add(
609	                        egui::TextEdit::singleline(&mut cmd.to_string().as_str())
610	                            .font(egui::TextStyle::Monospace)
611	                            .desired_width(f32::INFINITY)
612	                            .interactive(false),
613	                    );
614	                });
615	            if ui.small_button("Copy").clicked() {
616	                ui.ctx().copy_text(cmd.to_string());
617	            }
618	        });
