621	    // ── Step: ConfigurePtt ───────────────────────────────────────────────────
622	
623	    fn show_configure_ptt(
624	        ui: &mut egui::Ui,
625	        state: &mut FirstRunState,
626	        ptt: &mut PttCaptureState,
627	    ) {
628	        ui.heading("Step 4 of 4: Configure PTT key");
629	        ui.add_space(8.0);
630	        ui.label("Click 'Listen for key', then press the key you want to use as Push-to-Talk.");
631	        ui.add_space(8.0);
632	
633	        if ptt.listening {
634	            ui.spinner();
635	            ui.label("Listening… press any key now.");
636	        } else if !ptt.listening && ptt.handle.is_none() && ui.button("Listen for key").clicked() {
637	            ptt.error = None;
638	            let captured = Arc::clone(&ptt.captured_key);
639	            let handle = std::thread::spawn(move || {
640	                capture_first_keypress(captured);
641	            });
642	            ptt.handle = Some(handle);
643	            ptt.listening = true;
644	        }
645	
646	        if let Some(err) = &ptt.error {
647	            ui.add_space(8.0);
648	            ui.colored_label(egui::Color32::RED, err.as_str());
649	        }
650	
651	        ui.add_space(8.0);
652	        ui.label("Or enter a key name manually (e.g. KEY_GRAVE, KEY_F13):");
653	        let mut manual_key = String::new();
654	        let resp = ui.text_edit_singleline(&mut manual_key);
655	        if resp.lost_focus() && ui.input(|i| i.key_pressed(egui::Key::Enter)) {
656	            let key_name = manual_key.trim().to_string();
657	            if !key_name.is_empty() {
658	                match write_ptt_key_to_config(&key_name) {
659	                    Ok(()) => {
660	                        info!(key = %key_name, "PTT key written to config (manual entry)");
661	                        *state = probe::run();
662	                    }
663	                    Err(e) => {
664	                        ptt.error = Some(format!("Failed to save key: {e}"));
665	                    }
666	                }
667	            }
668	        }
669	    }
670	
671	    // ── PTT capture thread ───────────────────────────────────────────────────
672	
673	    /// Open the first readable keyboard evdev device and wait for the first KeyDown event.
674	    /// Stores the key name in `captured` and returns.
675	    fn capture_first_keypress(captured: Arc<Mutex<Option<String>>>) {
676	        info!("PTT capture thread started");
677	
678	        let device = match find_keyboard_device() {
679	            Some(d) => d,
680	            None => {
681	                error!("PTT capture: no readable keyboard device found in /dev/input/event*");
682	                return;
683	            }
684	        };
685	
686	        info!(
687	            device = device.name().unwrap_or("unknown"),
688	            "PTT capture: using device"
689	        );
690	
691	        let mut device = device;
692	        loop {
693	            match device.fetch_events() {
694	                Ok(events) => {
695	                    for event in events {
696	                        if let EventSummary::Key(_, key, 1) = event.destructure() {
697	                            let name = format!("{key:?}");
698	                            info!(key = %name, "PTT capture: key pressed");
699	                            if let Ok(mut guard) = captured.lock() {
700	                                *guard = Some(name);
701	                            }
702	                            return;
703	                        }
704	                    }
705	                }
706	                Err(e) => {
707	                    error!(reason = %e, "PTT capture: device read error");
708	                    return;
709	                }
710	            }
711	        }
712	    }
713	
714	    fn find_keyboard_device() -> Option<Device> {
715	        // Prefer devices that report standard keyboard keys (KEY_A is a reliable indicator)
716	        for (_path, device) in evdev::enumerate() {
717	            if device
718	                .supported_keys()
719	                .is_some_and(|keys| keys.contains(evdev::KeyCode::KEY_A))
720	            {
721	                return Some(device);
722	            }
723	        }
724	        None
725	    }
726	
727	    // ── Config file write ────────────────────────────────────────────────────
728	
729	    /// Write `key: <key_name>` to the ptt section of the config file.
730	    ///
731	    /// Reads the existing config, replaces the ptt.key line if present,
732	    /// or appends a ptt section if the file has no ptt.key line.
733	    fn write_ptt_key_to_config(key_name: &str) -> std::io::Result<()> {
734	        let path = crate::ui::probe::config_path_for_display();
735	        let path = PathBuf::from(path);
736	
737	        let contents = std::fs::read_to_string(&path).unwrap_or_default();
738	        let new_contents = rewrite_ptt_key(&contents, key_name);
739	        std::fs::write(&path, new_contents)
740	    }
741	
742	    /// Pure function: rewrite config text to set ptt.key = key_name.
743	    ///
744	    /// If a `key: KEY_*` line already exists, replaces it.
745	    /// If a `# key:` commented line exists, replaces that.
746	    /// Otherwise appends a ptt block at the end.
747	    pub(crate) fn rewrite_ptt_key(config: &str, key_name: &str) -> String {
748	        let mut found = false;
749	        let mut lines: Vec<String> = config
750	            .lines()
751	            .map(|line| {
752	                let trimmed = line.trim();
753	                // Match existing key: line (active or commented)
754	                if !found
755	                    && (trimmed.starts_with("key:") || trimmed.starts_with("# key:"))
756	                    && trimmed.contains("KEY_")
757	                {
758	                    found = true;
759	                    // Preserve indentation
760	                    let indent = line.len() - line.trim_start().len();
761	                    format!("{}key: {key_name}", " ".repeat(indent))
762	                } else {
763	                    line.to_string()
764	                }
765	            })
766	            .collect();
767	
768	        if !found {
769	            lines.push(String::new());
770	            lines.push("ptt:".to_string());
771	            lines.push(format!("  key: {key_name}"));
772	        }
773	
774	        let mut result = lines.join("\n");
775	        if !result.ends_with('\n') {
776	            result.push('\n');
777	        }
778	        result
779	    }
780	}
