104	/// Persist the current UI state to `~/.config/vibe-attack/config.yaml` atomically.
105	///
106	/// Clones `current`, patches the three user-editable fields (`stt.confidence_threshold`,
107	/// `audio.device`, `ptt.key`), serializes to YAML, writes to a sibling `.tmp` file, and
108	/// renames it into place so a crash during write never leaves a partial file.
109	///
110	/// # Note on `ActivationMode`
111	/// `mode` (PTT vs Wake) is a runtime-only flag in M008 and is NOT persisted to YAML here —
112	/// it has no field in `Config`. The caller (T03) sends `SetMode` over the control socket
113	/// to change the running daemon's mode. Adding a `mode` YAML field would change the schema
114	/// and is deferred to a later milestone.
115	pub fn save_app_to_config(
116	    app: &ConfigApp,
117	    current: &Config,
118	    path_override: Option<&std::path::Path>,
119	) -> anyhow::Result<Config> {
120	    let mut cfg = current.clone();
121	    cfg.stt.confidence_threshold = app.threshold_pct as f32 / 100.0;
122	    cfg.audio.device = app.input_device.clone();
123	    cfg.ptt.key = app.ptt_binding.clone();
124	
125	    let yaml = serde_yaml_ng::to_string(&cfg)
126	        .map_err(|e| anyhow::anyhow!("Failed to serialize config: {e}"))?;
127	
128	    let dest = match path_override {
129	        Some(p) => p.to_path_buf(),
130	        None => default_config_path()?,
131	    };
132	
133	    // Atomic write: write to a sibling .tmp then rename so partial writes are never visible.
134	    let tmp = dest.with_extension("yaml.tmp");
135	    std::fs::write(&tmp, &yaml)
136	        .map_err(|e| anyhow::anyhow!("Failed to write temp config {}: {e}", tmp.display()))?;
137	    std::fs::rename(&tmp, &dest)
138	        .map_err(|e| anyhow::anyhow!("Failed to rename temp config to {}: {e}", dest.display()))?;
139	
140	    Ok(cfg)
141	}
