143	/// Load profile names from the XDG config profiles directory.
144	///
145	/// Returns the directory names of all subdirectories that contain a `pack.yaml`
146	/// file, matching the format expected by `Pack::load_from_dir` and
147	/// `handle_switch_profile`. Flat `.yaml` files at the profiles root are ignored.
148	pub fn load_profiles() -> Vec<String> {
149	    let profiles_dir = BaseDirectories::with_prefix("vibe-attack")
150	        .get_config_home()
151	        .map(|p| p.join("profiles"));
152	
153	    let Some(dir) = profiles_dir else {
154	        info!(count = 0, "Profiles dir not resolvable; no profiles loaded");
155	        return Vec::new();
156	    };
157	
158	    if !dir.is_dir() {
159	        info!(path = %dir.display(), count = 0, "Profiles dir not found");
160	        return Vec::new();
161	    }
162	
163	    let mut names: Vec<String> = std::fs::read_dir(&dir)
164	        .into_iter()
165	        .flatten()
166	        .flatten()
167	        .filter_map(|entry| {
168	            let path = entry.path();
169	            if entry.file_type().ok()?.is_dir() && path.join("pack.yaml").exists() {
170	                path.file_name()
171	                    .and_then(|s| s.to_str())
172	                    .map(|s| s.to_string())
173	            } else {
174	                None
175	            }
176	        })
177	        .collect();
178	
179	    names.sort();
180	    info!(path = %dir.display(), count = names.len(), "Profiles loaded");
181	    names
182	}
