20	/// Shared state polled from the daemon; updated by the background poll task.
21	#[derive(Clone, Default)]
22	struct TrayState {
23	    /// None = daemon not running.
24	    daemon_state: Option<DaemonState>,
25	    /// Active profile name reported by the daemon (None = none loaded or daemon stopped).
26	    active_profile: Option<String>,
27	    /// Profile names discovered from the XDG config directory.
28	    profiles: Vec<String>,
