142	/// Return the XDG/FreeDesktop icon name for a given daemon state.
143	///
144	/// `None` means the daemon is not running — treat the same as Muted so the
145	/// tray icon makes it obvious the mic is inactive.  `Listening` gets a
146	/// distinct "high" variant to distinguish the wake-word window from idle.
147	pub(crate) fn icon_name_for_state(state: Option<&DaemonState>) -> &'static str {
148	    match state {
149	        None | Some(DaemonState::Muted) => "audio-input-microphone-muted",
150	        Some(DaemonState::Idle) | Some(DaemonState::Recording) => "audio-input-microphone",
151	        Some(DaemonState::Listening) => "audio-input-microphone-high",
152	    }
153	}
