199	            .unwrap_or_default();
200	
201	        let mut cached_config = None;
202	
203	        if setup_complete {
204	            config.profiles = load_profiles();
205	            mic = spawn_mic_level_thread();
206	
207	            match load_config_into_app(&mut config, None) {
208	                Ok(cfg) => cached_config = Some(cfg),
209	                Err(e) => config.set_status(format!("Could not load config.yaml: {e}")),
210	            }
211	        } else {
212	            // Defer mic/profile load until after wizard completes
213	            mic = MicLevelState {
214	                level: Arc::new(AtomicU32::new(0)),
215	                no_device: false,
216	                _handle: None,
217	            };
218	        }
219	
220	        Self {
221	            first_run,
222	            config,
223	            ptt: PttCaptureState::new(),
224	            dl: ModelDownloadState::new(),
225	            uinput: UinputSetupState::new(),
226	            config_example_contents,
227	            hd2_profile_contents,
228	            mic,
229	            log_rx,
