239	impl eframe::App for VibeAttackConfigApp {
240	    fn ui(&mut self, ui: &mut egui::Ui, _frame: &mut eframe::Frame) {
241	        let ctx = ui.ctx().clone();
242	
243	        // Honour "Open Config" requests from the tray.
244	        if self.tray.as_ref().is_some_and(|t| t.take_open_request()) {
245	            ctx.send_viewport_cmd(egui::ViewportCommand::Focus);
246	        }
247	
248	        // Repaint at ~10Hz for mic level updates when in main config view.
249	        if self.first_run.is_setup_complete() {
250	            ctx.request_repaint_after(std::time::Duration::from_millis(100));
251	        }
252	
253	        // Repaint faster while PTT capture thread is listening.
254	        if self.ptt.listening {
255	            ctx.request_repaint_after(std::time::Duration::from_millis(50));
256	        }
257	
258	        // Repaint while model download is in progress.
259	        if self.dl.is_running() {
260	            ctx.request_repaint_after(std::time::Duration::from_millis(250));
261	        }
262	
263	        // Repaint while uinput setup actions are running.
264	        use vibe_attack::ui::wizard::SetupActionStatus;
265	        if matches!(self.uinput.modprobe, SetupActionStatus::Running)
266	            || matches!(self.uinput.usermod, SetupActionStatus::Running)
267	        {
268	            ctx.request_repaint_after(std::time::Duration::from_millis(200));
269	        }
270	
271	        // Drain log channel.
272	        while let Ok(line) = self.log_rx.try_recv() {
273	            self.config.add_log_line(line);
274	        }
275	
276	        // Update mic level from atomic.
277	        self.config.mic_level = self.mic.current_level();
278	        self.config.mic_no_device = self.mic.no_device;
279	
280	        // Refresh daemon-running status each frame (cheap socket stat).
281	        self.config.daemon_running = vibe_attack::control::client::is_daemon_running();
282	
283	        // Detect wizard completion and load profiles + start mic thread.
284	        if self.setup_just_completed {
285	            self.setup_just_completed = false;
286	            self.config.profiles = load_profiles();
287	            self.mic = spawn_mic_level_thread();
288	
289	            match load_config_into_app(&mut self.config, None) {
290	                Ok(cfg) => self.cached_config = Some(cfg),
291	                Err(e) => self.config.set_status(format!("Could not load config.yaml: {e}")),
292	            }
293	        }
294	
295	        ui.heading("Vibe Attack");
296	        ui.separator();
297	
298	        let was_incomplete = !self.first_run.is_setup_complete();
299	
300	        if !self.first_run.is_setup_complete() {
301	            show_wizard(
302	                ui,
303	                &mut self.first_run,
304	                &mut self.ptt,
305	                &mut self.dl,
306	                &mut self.uinput,
307	                self.config_example_contents,
308	                self.hd2_profile_contents,
309	            );
310	            // Detect transition to complete
311	            if was_incomplete && self.first_run.is_setup_complete() {
312	                self.setup_just_completed = true;
313	            }
314	        } else {
315	            show_main_config(ui, self);
316	        }
317	    }
318	}
