464	fn handle_save(app: &mut VibeAttackConfigApp) {
465	    use vibe_attack::control::client::send_command;
466	    use vibe_attack::control::protocol::ControlRequest;
467	
468	    let Some(cached) = app.cached_config.as_ref() else {
469	        app.config.set_status("No config loaded — cannot save.");
470	        return;
471	    };
472	
473	    match save_app_to_config(&app.config, cached, None) {
474	        Err(e) => {
475	            app.config.set_status(format!("Save failed: {e}"));
476	            return;
477	        }
478	        Ok(updated) => {
479	            app.cached_config = Some(updated);
480	        }
481	    }
482	
483	    if !app.config.daemon_running {
484	        app.config
485	            .set_status("Saved to disk — daemon not running, runtime changes skipped.");
486	        return;
487	    }
488	
489	    // Dispatch four control commands; collect any failures.
490	    let commands = [
491	        ControlRequest::SetMode { mode: app.config.mode.clone() },
492	        ControlRequest::SetThreshold {
493	            threshold: app.config.threshold_pct as f32 / 100.0,
494	        },
495	        ControlRequest::SetInputDevice {
496	            device: app.config.input_device.clone(),
497	        },
498	        ControlRequest::SetPttBinding {
499	            key: app.config.ptt_binding.clone(),
500	        },
501	    ];
502	
503	    let mut errors: Vec<String> = Vec::new();
504	    for cmd in commands {
505	        let label = format!("{cmd:?}");
506	        if let Err(e) = send_command(cmd) {
507	            errors.push(format!("Failed to send {label}: {e}"));
508	        }
509	    }
510	
511	    if errors.is_empty() {
512	        app.config.set_status("Saved and applied.");
513	    } else {
514	        app.config.set_status(errors.join("; "));
515	    }
516	}
