518	fn main() -> eframe::Result<()> {
519	    use tracing_subscriber::prelude::*;
520	
521	    let args: Vec<String> = std::env::args().collect();
522	
523	    if args.iter().any(|a| a == "--help" || a == "-h") {
524	        println!("Usage: vibe-attack-config [--skip-wizard] [--help]");
525	        println!();
526	        println!("  --skip-wizard   Bypass first-run wizard regardless of probe state");
527	        println!("  --help, -h      Print this help and exit");
528	        return Ok(());
529	    }
530	
531	    let skip_wizard = args.iter().any(|a| a == "--skip-wizard");
532	
533	    // Log channel: bounded to 500 entries; oldest are dropped under pressure.
534	    let (log_tx, log_rx) = mpsc::sync_channel(500);
535	
536	    tracing_subscriber::registry()
537	        .with(tracing_subscriber::fmt::layer())
538	        .with(ChannelLayer { tx: log_tx })
539	        .init();
540	
541	    let options = eframe::NativeOptions {
542	        viewport: egui::ViewportBuilder::default()
543	            .with_title("Vibe Attack Config")
544	            .with_inner_size([720.0, 520.0]),
545	        ..Default::default()
546	    };
547	
548	    eframe::run_native(
549	        "Vibe Attack Config",
550	        options,
551	        Box::new(move |_cc| Ok(Box::new(VibeAttackConfigApp::new(log_rx, skip_wizard)))),
552	    )
553	}
