37	fn check_config() -> bool {
38	    let Some(path) = xdg_config_path() else {
39	        warn!(check = "config", reason = "could not resolve XDG config path");
40	        return false;
41	    };
42	    if path.is_file() {
43	        true
44	    } else {
45	        warn!(
46	            check = "config",
47	            path = %path.display(),
48	            reason = "config file not found"
49	        );
50	        false
51	    }
52	}
53	
54	fn check_model() -> bool {
55	    let Some(path) = xdg_data_model_path() else {
56	        warn!(check = "model", reason = "could not resolve XDG data path");
57	        return false;
58	    };
59	    match path.metadata() {
60	        Ok(m) if m.len() > 0 => true,
61	        Ok(_) => {
62	            warn!(
63	                check = "model",
64	                path = %path.display(),
65	                reason = "model file exists but is empty"
66	            );
67	            false
68	        }
69	        Err(_) => {
70	            warn!(
71	                check = "model",
72	                path = %path.display(),
73	                reason = "model file not found"
74	            );
75	            false
76	        }
77	    }
78	}
79	
80	fn check_uinput() -> bool {
81	    match fs::OpenOptions::new()
82	        .read(true)
83	        .write(true)
84	        .open("/dev/uinput")
85	    {
86	        Ok(_) => true,
87	        Err(e) => {
88	            warn!(
89	                check = "uinput",
90	                reason = %e,
91	                "cannot open /dev/uinput for read+write"
92	            );
93	            false
94	        }
95	    }
96	}
97	
98	fn check_ptt() -> bool {
99	    let Some(path) = xdg_config_path() else {
100	        return false;
101	    };
102	    let Ok(mut f) = fs::File::open(&path) else {
103	        warn!(
104	            check = "ptt",
105	            path = %path.display(),
106	            reason = "config file not readable"
107	        );
108	        return false;
109	    };
110	    let mut contents = String::new();
111	    if f.read_to_string(&mut contents).is_err() {
112	        warn!(check = "ptt", reason = "could not read config file");
113	        return false;
114	    }
115	    // Matches lines like:  key: KEY_LEFTCTRL
116	    if contents.lines().any(|l| {
117	        let t = l.trim();
118	        t.starts_with("key:") && t.contains("KEY_")
119	    }) {
120	        true
121	    } else {
122	        warn!(
123	            check = "ptt",
124	            path = %path.display(),
125	            reason = "no 'key: KEY_*' entry found in config — set ptt.key"
126	        );
127	        false
128	    }
129	}
