131	/// Probe the environment and return a populated [`FirstRunState`].
132	///
133	/// Each failed check emits a `tracing::warn` with the check name and reason.
134	pub fn run() -> FirstRunState {
135	    let config_path = xdg_config_path()
136	        .map(|p| p.display().to_string())
137	        .unwrap_or_else(|| "unknown".to_string());
138	    info!(config_path, "probing first-run environment");
139	
140	    FirstRunState::from_checks(
141	        check_config(),
142	        check_model(),
143	        check_uinput(),
144	        check_ptt(),
145	    )
146	}
